// 가재(Gajae)가 생성한 브리핑을 텔레그램으로 전송합니다.
const briefing = $json.choices?.[0]?.message?.content || $json.aiContent;

if (!briefing) {
  throw new Error('가재가 브리핑 내용을 생성하지 않았습니다.');
}

const token = '7970537683:AAH0QmWImg0LKzEjHY7fn5kWwcpgIzVmoWY';
const chatId = '1290448372';

// 텔레그램 메시지 전송
try {
  const response = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      chat_id: chatId,
      text: briefing,
      parse_mode: 'Markdown'
    })
  });

  const result = await response.json();

  return {
    success: response.ok,
    message_id: result.result?.message_id,
    status_code: response.status,
    briefing_preview: briefing.substring(0, 50) + "..."
  };
} catch (error) {
  return {
    success: false,
    error: error.message
  };
}
